// Requête REST Supabase générique
async function supaFetch(path, method = "GET", body = null) {
  const opts = {
    method,
    headers: {
      "apikey": SUPA_KEY,
      "Authorization": "Bearer " + SUPA_KEY,
      "Content-Type": "application/json",
      "Prefer": method === "POST" ? "return=representation" : "",
    },
  };
  if (body !== null) opts.body = JSON.stringify(body);
  const res = await fetch(SUPA_URL + "/rest/v1" + path, opts);
  if (!res.ok) {
    const err = await res.text();
    throw new Error("Supabase " + method + " " + path + " → " + res.status + " " + err);
  }
  const text = await res.text();
  return text ? JSON.parse(text) : [];
}

// Conversion snake_case Supabase → camelCase app (champs spécifiques)
function rowToItem(table, row) {
  if (!row) return row;
  const r = { ...row };
  // Champs communs
  if ("image_url"   in r) { r.imageUrl   = r.image_url;   delete r.image_url; }
  if ("image_data"  in r) { r.imageData  = r.image_data;  delete r.image_data; }
  if ("image_url2"  in r) { r.imageUrl2  = r.image_url2;  delete r.image_url2; }
  if ("image_data2" in r) { r.imageData2 = r.image_data2; delete r.image_data2; }
  if ("schema_url"  in r) { r.schemaUrl  = r.schema_url;  delete r.schema_url; }
  if ("schema_data" in r) { r.schemaData = r.schema_data; delete r.schema_data; }
  if ("photo_url"   in r) { r.photoUrl   = r.photo_url;   delete r.photo_url; }
  if ("photo_data"  in r) { r.photoData  = r.photo_data;  delete r.photo_data; }
  if ("credit_photo" in r) { r.creditPhoto = r.credit_photo; delete r.credit_photo; }
  if ("nom_commercial" in r) { r.nomCommercial = r.nom_commercial; delete r.nom_commercial; }
  if ("dilution_standard" in r) { r.dilutionStandard = r.dilution_standard; delete r.dilution_standard; }
  if ("has_second_ecg" in r) { r.hasSecondEcg = r.has_second_ecg; delete r.has_second_ecg; }
  if ("second_title" in r) { r.secondTitle = r.second_title; delete r.second_title; }
  if ("has_second_image" in r) { r.hasSecondImage = r.has_second_image; delete r.has_second_image; }
  if ("video_url"   in r) { r.videoUrl   = r.video_url;   delete r.video_url; }
  if ("is_video"    in r) { r.isVideo    = r.is_video;    delete r.is_video; }
  if ("lien_url"    in r) { r.lienUrl    = r.lien_url;    delete r.lien_url; }
  if ("is_pinned"   in r) { r.isPinned   = r.is_pinned;   delete r.is_pinned; }
  // Reco Flash : mapping spécifique
  if ("date_publication" in r) { r.datePublication = r.date_publication; delete r.date_publication; }
  if ("url_pdf"     in r) { r.urlPdf     = r.url_pdf;     delete r.url_pdf; }
  // Quiz : mapping spécifique
  if ("estimated_min" in r) { r.estimatedMin = r.estimated_min; delete r.estimated_min; }
  // Normalise tags : on garde un ARRAY pour que .map() fonctionne partout en lecture
  // (la conversion string→array pour le formulaire d'édition se fait à l'init du form)
  if (!Array.isArray(r.tags)) {
    if (typeof r.tags === "string" && r.tags.trim()) {
      r.tags = r.tags.split(",").map(t => t.trim()).filter(Boolean);
    } else {
      r.tags = [];
    }
  }
  // Filet de sécurité : tout champ snake_case restant est auto-converti en camelCase
  // (utile pour les colonnes ajoutées en DB sans mapping explicite — sauf created_at/updated_at)
  const SNAKE_PRESERVE = new Set(["created_at", "updated_at", "created_by"]);
  for (const key of Object.keys(r)) {
    if (key.includes("_") && !SNAKE_PRESERVE.has(key)) {
      const camel = key.replace(/_([a-z])/g, (_, c) => c.toUpperCase());
      if (camel !== key && !(camel in r)) {
        r[camel] = r[key];
        delete r[key];
      }
    }
  }
  return r;
}

// Conversion camelCase app → snake_case Supabase
function itemToRow(table, item) {
  const r = { ...item };
  delete r.id;           // géré par Supabase
  delete r.created_at;
  delete r.updated_at;
  delete r.imageData;    // stocké en Storage, pas en DB
  delete r.imageData2;
  delete r.schemaData;
  delete r.photoData;
  // On retire aussi les données binaires des médias pour l'upsert DB
  if (r.medias) r.medias = (r.medias || []).map(m => ({ url: m.url, name: m.name, isVideo: m.isVideo, credit: m.credit || "" }));

  if ("imageUrl"         in r) { r.image_url          = r.imageUrl;         delete r.imageUrl; }
  if ("imageUrl2"        in r) { r.image_url2         = r.imageUrl2;        delete r.imageUrl2; }
  if ("schemaUrl"        in r) { r.schema_url         = r.schemaUrl;        delete r.schemaUrl; }
  if ("photoUrl"         in r) { r.photo_url          = r.photoUrl;         delete r.photoUrl; }
  if ("creditPhoto"      in r) { r.credit_photo       = r.creditPhoto;      delete r.creditPhoto; }
  if ("nomCommercial"    in r) { r.nom_commercial     = r.nomCommercial;    delete r.nomCommercial; }
  if ("dilutionStandard" in r) { r.dilution_standard  = r.dilutionStandard; delete r.dilutionStandard; }
  if ("hasSecondEcg"     in r) { r.has_second_ecg     = r.hasSecondEcg;     delete r.hasSecondEcg; }
  if ("secondTitle"      in r) { r.second_title       = r.secondTitle;      delete r.secondTitle; }
  if ("hasSecondImage"   in r) { r.has_second_image   = r.hasSecondImage;   delete r.hasSecondImage; }
  if ("videoUrl"         in r) { r.video_url          = r.videoUrl;         delete r.videoUrl; }
  if ("isVideo"          in r) { r.is_video           = r.isVideo;          delete r.isVideo; }
  if ("lienUrl"          in r) { r.lien_url           = r.lienUrl;          delete r.lienUrl; }
  if ("isPinned"         in r) { r.is_pinned          = r.isPinned;         delete r.isPinned; }
  // Reco Flash : mapping spécifique
  if ("datePublication"  in r) { r.date_publication   = r.datePublication;  delete r.datePublication; }
  if ("urlPdf"           in r) { r.url_pdf            = r.urlPdf;           delete r.urlPdf; }
  // Quiz : mapping spécifique
  if ("estimatedMin"     in r) { r.estimated_min      = r.estimatedMin;     delete r.estimatedMin; }
  // Strings vides → null (sinon PostgreSQL rejette pour les colonnes typées date, integer, etc.)
  // Liste blanche des colonnes connues qui doivent passer en null si vides
  const NULLABLE_IF_EMPTY = ["date_publication", "url_pdf", "video_url", "lien_url", "schema_url", "photo_url", "image_url", "image_url2", "second_title", "credit", "credit_photo", "icon", "color", "subtitle", "category", "description", "context", "question", "diag", "type", "emoji"];
  for (const k of NULLABLE_IF_EMPTY) {
    if (k in r && (r[k] === "" || r[k] === undefined)) r[k] = null;
  }
  // tags : string→array pour Supabase
  if (typeof r.tags === "string") r.tags = r.tags ? r.tags.split(",").map(t => t.trim()).filter(Boolean) : [];
  // Filet de sécurité : tout champ camelCase restant est auto-converti en snake_case
  // (utile si un nouveau champ est ajouté en DB sans mapping explicite)
  for (const key of Object.keys(r)) {
    if (/[A-Z]/.test(key)) {
      const snake = key.replace(/[A-Z]/g, c => "_" + c.toLowerCase());
      if (snake !== key && !(snake in r)) {
        r[snake] = r[key];
        delete r[key];
      }
    }
  }
  return r;
}

// Upload fichier base64 → Supabase Storage (bucket sau-media)
async function uploadMedia(fileName, base64Data) {
  if (!base64Data || !fileName) return null;
  const [header, data] = base64Data.split(",");
  const mime = (header.match(/:(.*?);/) || [])[1] || "application/octet-stream";
  const bytes = atob(data);
  const arr = new Uint8Array(bytes.length);
  for (let i = 0; i < bytes.length; i++) arr[i] = bytes.charCodeAt(i);
  const blob = new Blob([arr], { type: mime });
  const path = "uploads/" + Date.now() + "_" + fileName.replace(/[^a-zA-Z0-9._-]/g, "_");
  const res = await fetch(`${SUPA_URL}/storage/v1/object/sau-media/${path}`, {
    method: "POST",
    headers: { "apikey": SUPA_KEY, "Authorization": "Bearer " + SUPA_KEY, "Content-Type": mime },
    body: blob,
  });
  if (!res.ok) throw new Error("Storage upload failed: " + await res.text());
  return `${SUPA_URL}/storage/v1/object/public/sau-media/${path}`;
}

// Compatibilité : safeGet/safeSet utilisés par notifications + favoris restent en localStorage
async function safeGet(key) {
  // Pour les clés liées aux tables Supabase, on passe par l'API
  if (TABLE_MAP[key]) {
    try {
      const rows = await supaFetch("/" + TABLE_MAP[key] + "?order=created_at.asc&limit=1000");
      const items = rows.map(r => rowToItem(TABLE_MAP[key], r));
      return { key, value: JSON.stringify(items) };
    } catch(e) { console.warn("safeGet Supabase", key, e); return null; }
  }
  // Clés locales (notifications, favoris)
  try {
    const val = localStorage.getItem("sau_" + key);
    if (val === null) return null;
    return { key, value: val };
  } catch(e) { return null; }
}

async function safeSet(key, value) {
  // Pour les tables gérées → no-op ici (les écritures passent par addItem/removeItem)
  if (TABLE_MAP[key]) return;
  try { localStorage.setItem("sau_" + key, value); } catch(e) {}
}

const LOGO_HOSP = "data:image/png;base64,";

// Helper storage : retourne null si clé absente, évite les try/catch partout

// ─── DataStore : store global partagé entre tous les modules ──────────────────
const DataCtx = React.createContext(null);

function useData() { return React.useContext(DataCtx); }

function DataProvider({ children }) {
  const [store, setStore] = React.useState({
    ecgs: [], imagerie: [], agenda: [],
    divers: [], dilutions: [], gestes: [], retex: [],
    contacts: [], recoflash: [], quizzes: [], loaded: false
  });

  React.useEffect(() => { loadAll(); }, []);

  async function loadFiles(items, fileFields) {
    for (const item of items) {
      for (const field of fileFields) {
        const urlField = field + "Url";
        const dataField = field + "Data";
        if (item[urlField]) {
          const fd = await safeGet("file_" + item[urlField]);
          if (fd) item[dataField] = fd.value;
        }
      }
      if (item.medias?.length) {
        item.medias = await Promise.all(item.medias.map(async m => {
          const fd = await safeGet("file_" + m.url);
          return fd ? { ...m, data: fd.value } : m;
        }));
      }
    }
    return items;
  }

  async function loadAll() {
    const next = { loaded: false };

    const re = await safeGet("admin_ecgs");
    next.ecgs = re ? await loadFiles(JSON.parse(re.value), ["image"]) : [];

    const ri = await safeGet("admin_imagerie");
    next.imagerie = ri ? await loadFiles(JSON.parse(ri.value), ["image"]) : [];

    const ra = await safeGet("admin_agenda");
    next.agenda = ra ? await loadFiles(JSON.parse(ra.value), ["image"]) : [];

    const rd = await safeGet("admin_divers");
    next.divers = rd ? await loadFiles(JSON.parse(rd.value), ["image"]) : [];

    const rdil = await safeGet("admin_dilutions");
    next.dilutions = rdil ? await loadFiles(JSON.parse(rdil.value), ["schema", "photo"]) : [];

    const rg = await safeGet("admin_gestes");
    next.gestes = rg ? await loadFiles(JSON.parse(rg.value), ["image"]) : [];

    const rr = await safeGet("retex_submissions");
    next.retex = rr ? JSON.parse(rr.value) : [];

    const rc = await safeGet("admin_contacts");
    next.contacts = rc ? JSON.parse(rc.value) : [];

    const rrf = await safeGet("admin_recoflash");
    next.recoflash = rrf ? JSON.parse(rrf.value) : [];

    const rq = await safeGet("admin_quizzes");
    next.quizzes = rq ? JSON.parse(rq.value) : [];

    next.loaded = true;
    setStore(next);
  }

  async function save(key, storeKey, items, stripFields = []) {
    const toSave = items.map(item => {
      const copy = { ...item };
      for (const f of stripFields) delete copy[f];
      if (copy.medias) copy.medias = (copy.medias || []).map(m => ({ url: m.url, name: m.name, isVideo: m.isVideo }));
      return copy;
    });
    await safeSet(key, JSON.stringify(toSave));
    setStore(prev => ({ ...prev, [storeKey]: items }));
  }

  async function saveFiles(item, fileFields) {
    for (const field of fileFields) {
      const dataField = field + "Data";
      const urlField = field + "Url";
      if (item[dataField] && item[urlField]) {
        await safeSet("file_" + item[urlField], item[dataField]);
      }
    }
    if (item.medias) {
      for (const m of item.medias) {
        if (m.data && m.url) await safeSet("file_" + m.url, m.data);
      }
    }
  }

  async function addItem(storeKey, storageKey, item, fileFields = []) {
    await saveFiles(item, fileFields);
    // Si la clé pointe vers une table Supabase → vrai INSERT POST
    if (TABLE_MAP[storageKey]) {
      const row = itemToRow(TABLE_MAP[storageKey], item);
      console.log("[addItem] POST /" + TABLE_MAP[storageKey], row);
      try {
        const rows = await supaFetch("/" + TABLE_MAP[storageKey], "POST", row);
        const newItem = rowToItem(TABLE_MAP[storageKey], Array.isArray(rows) ? rows[0] : rows);
        console.log("[addItem] success, newItem=", newItem);
        setStore(prev => ({
          ...prev,
          [storeKey]: [...(prev[storeKey] || []), newItem],
        }));
        return newItem;
      } catch(e) {
        console.error("[addItem] Supabase error on " + storageKey, e);
        console.error("[addItem] payload was", row);
        alert("Erreur lors de l'enregistrement :\n\n" + e.message + "\n\n(Ouvre la console F12 pour les détails)");
        throw e;
      }
    }
    // Fallback localStorage (clés non mappées)
    const newItem = { ...item, id: item.id || Date.now() };
    const exists = store[storeKey].find(x => x.id === newItem.id);
    const updated = exists
      ? store[storeKey].map(x => x.id === newItem.id ? newItem : x)
      : [...store[storeKey], newItem];
    await save(storageKey, storeKey, updated, fileFields.map(f => f + "Data"));
  }

  async function removeItem(storeKey, storageKey, id, stripFields = []) {
    // Si la clé pointe vers une table Supabase → vrai DELETE
    if (TABLE_MAP[storageKey]) {
      try {
        await supaFetch("/" + TABLE_MAP[storageKey] + "?id=eq." + encodeURIComponent(id), "DELETE");
        setStore(prev => ({
          ...prev,
          [storeKey]: (prev[storeKey] || []).filter(x => x.id !== id),
        }));
        return;
      } catch(e) {
        console.error("removeItem Supabase", storageKey, e);
        alert("Erreur lors de la suppression : " + e.message);
        throw e;
      }
    }
    const updated = store[storeKey].filter(x => x.id !== id);
    await save(storageKey, storeKey, updated, stripFields);
  }

  async function updateItem(storeKey, storageKey, item, fileFields = []) {
    await saveFiles(item, fileFields);
    // Si la clé pointe vers une table Supabase → vrai PATCH
    if (TABLE_MAP[storageKey]) {
      const row = itemToRow(TABLE_MAP[storageKey], item);
      try {
        const rows = await supaFetch(
          "/" + TABLE_MAP[storageKey] + "?id=eq." + encodeURIComponent(item.id),
          "PATCH",
          row
        );
        const updatedItem = rowToItem(TABLE_MAP[storageKey], Array.isArray(rows) ? rows[0] : rows);
        setStore(prev => ({
          ...prev,
          [storeKey]: (prev[storeKey] || []).map(x => x.id === item.id ? (updatedItem || item) : x),
        }));
        return updatedItem;
      } catch(e) {
        console.error("updateItem Supabase", storageKey, e);
        alert("Erreur lors de la mise à jour : " + e.message);
        throw e;
      }
    }
    const updated = store[storeKey].map(x => x.id === item.id ? item : x);
    await save(storageKey, storeKey, updated, fileFields.map(f => f + "Data"));
  }

  async function addRetexItem(item) {
    // Strippe les data: base64 des médias (URLs Storage seulement, plus les data)
    const cleanItem = {
      ...item,
      medias: (item.medias || []).filter(m => !m._uploading).map(m => ({
        url: m.url, name: m.name, isVideo: m.isVideo, credit: m.credit || ""
      })),
    };
    // POST Supabase via supaFetch
    const row = itemToRow("retex", cleanItem);
    try {
      const rows = await supaFetch("/retex", "POST", row);
      const created = rowToItem("retex", Array.isArray(rows) ? rows[0] : rows);
      setStore(prev => ({ ...prev, retex: [created, ...prev.retex.filter(x => x.id !== created.id)] }));
      return created;
    } catch(e) {
      console.error("addRetexItem error", e);
      alert("Erreur lors de la publication RETEX : " + e.message);
      throw e;
    }
  }

  async function removeRetexItem(id) {
    try {
      await supaFetch("/retex?id=eq." + encodeURIComponent(id), "DELETE");
      setStore(prev => ({ ...prev, retex: prev.retex.filter(x => x.id !== id) }));
    } catch(e) {
      console.error("removeRetexItem error", e);
      alert("Erreur lors de la suppression RETEX : " + e.message);
      throw e;
    }
  }

  async function updateRetex(item) {
    const cleanItem = {
      ...item,
      medias: (item.medias || []).filter(m => !m._uploading).map(m => ({
        url: m.url, name: m.name, isVideo: m.isVideo, credit: m.credit || ""
      })),
    };
    const row = itemToRow("retex", cleanItem);
    try {
      const rows = await supaFetch("/retex?id=eq." + encodeURIComponent(item.id), "PATCH", row);
      const updated = rowToItem("retex", Array.isArray(rows) ? rows[0] : rows) || cleanItem;
      setStore(prev => ({ ...prev, retex: prev.retex.map(x => x.id === item.id ? updated : x) }));
      return updated;
    } catch(e) {
      console.error("updateRetex error", e);
      alert("Erreur lors de la mise à jour RETEX : " + e.message);
      throw e;
    }
  }

  return (
    <DataCtx.Provider value={{ store, loadAll, addItem, removeItem, updateItem, addRetexItem, removeRetexItem, updateRetex }}>
      {children}
    </DataCtx.Provider>
  );
}

