    jambe_g_face:   { label:"Jambe G ant.",       pct:2.5, face:true },
    jambe_d_face:   { label:"Jambe D ant.",       pct:2.5, face:true },
    jambe_g_back:   { label:"Jambe G post.",      pct:2.5, face:false },
